 96→async function loadWidgetMaskDataUrl(race: Race): Promise<string> {
 97→  const cached = widgetMaskCache.get(race);
 98→  if (cached) return cached;
 99→
100→  const frame = (await loadBLPMips(getFrameTexturePath(race)))[0];
101→  if (!frame || frame.width <= 0 || frame.height <= 0) {
102→    throw new Error(`Invalid frame texture for ${race}`);
103→  }
104→
105→  const width = frame.width;
106→  const height = frame.height;
107→  const seedX = Math.round(width * 0.49);
108→  const seedY = Math.round(height * 0.34);
109→  const seed = findTransparentSeed(frame.data, width, height, seedX, seedY);
110→  if (seed < 0) {
111→    throw new Error(`Unable to locate clock aperture for ${race}`);
112→  }
113→
114→  const aperture = new Uint8Array(width * height);
115→  const queue = new Int32Array(width * height);
116→  let head = 0;
117→  let tail = 0;
118→  queue[tail++] = seed;
119→  aperture[seed] = 1;
120→
121→  while (head < tail) {
122→    const cur = queue[head++];
123→    const x = cur % width;
124→    const y = (cur / width) | 0;
125→    const neighbors = [
126→      [x - 1, y],
127→      [x + 1, y],
128→      [x, y - 1],
129→      [x, y + 1],
130→    ];
131→    for (const [nx, ny] of neighbors) {
132→      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
133→      const next = ny * width + nx;
134→      if (aperture[next]) continue;
135→      if (frame.data[next * 4 + 3] !== 0) continue;
136→      aperture[next] = 1;
137→      queue[tail++] = next;
138→    }
139→  }
140→
141→  const pixels = new Uint8ClampedArray(width * height * 4);
142→  for (let i = 0; i < width * height; i++) {
143→    const frameOpaque = frame.data[i * 4 + 3] > 0;
144→    const keep = frameOpaque || aperture[i] === 1;
145→    if (!keep) continue;
146→    const p = i * 4;
147→    pixels[p + 0] = 255;
148→    pixels[p + 1] = 255;
149→    pixels[p + 2] = 255;
150→    pixels[p + 3] = 255;
151→  }
152→
153→  const canvas = document.createElement('canvas');
154→  canvas.width = width;
155→  canvas.height = height;
156→  const ctx = canvas.getContext('2d');
157→  if (!ctx) throw new Error('Failed to create widget mask canvas');
158→  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
159→  const dataUrl = canvas.toDataURL('image/png');
160→  widgetMaskCache.set(race, dataUrl);
161→  return dataUrl;
162→}
