 49→const modelCache = new Map<string, ModelType>();
 50→const blpCache = new Map<string, ImageData[]>();
 51→
 52→function normalizeTexturePath(textureImage: string): string {
 53→  return textureImage.replaceAll('\\', '/').toLowerCase();
 54→}
 55→
 56→function getTexturePath(textureImage: string, race: Race): string | null {
 57→  const normalized = normalizeTexturePath(textureImage);
 58→  if (!normalized) return null;
 59→
 60→  const raceTexture = WORKER_UNIT_CONFIG[race].textures[normalized];
 61→  if (raceTexture) return raceTexture;
 62→  return null;
 63→}
